#include <stdio.h>
#include <stdlib.h>
#define MAX_CHEFS 1001

// Define a struct to represent a chef
typedef struct Chef {
    int index;
    int health;
    int is_old;
    struct Chef* superior;
    struct Chef** inferiors;
    int num_inferiors;
} Chef;

// Function to create a new chef
Chef* create_chef(int index) {
    Chef* chef = (Chef*) malloc(sizeof(Chef));
    chef->index = index;
    chef->health = 100;
    chef->is_old = 1;
    chef->superior = NULL;
    chef->inferiors = NULL;
    chef->num_inferiors = 0;
    return chef;
}

// Function to add an inferior to a chef
void add_inferior(Chef* chef, Chef* inferior) {
    chef->num_inferiors++;
    chef->inferiors = (Chef**) realloc(chef->inferiors, chef->num_inferiors * sizeof(Chef*));
    chef->inferiors[chef->num_inferiors - 1] = inferior;
}

// Function to propagate poison to inferiors
void propagate_poison(Chef* chef, int poison) {
    if (chef->health <= 0) return;
    chef->health -= poison;
    if (chef->health <= 0) {
        chef->is_old = 0;
    }
    for (int i = 0; i < chef->num_inferiors; i++) {
        propagate_poison(chef->inferiors[i], poison);
    }
}

// Function to count old inferiors
int count_old_inferiors(Chef* chef) {
    int count = 0;
    for (int i = 0; i < chef->num_inferiors; i++) {
        if (chef->inferiors[i]->is_old) count++;
        count += count_old_inferiors(chef->inferiors[i]);
    }
    return count;
}

int main() {
    int N;
    scanf("%d", &N);
    Chef* chefs[MAX_CHEFS];
    for (int i = 0; i <= N; i++) {
        chefs[i] = create_chef(i);
    }
    for (int i = 1; i <= N; i++) {
        int superior_index, chef_index;
        scanf("%d %d", &chef_index, &superior_index);
        chefs[chef_index]->superior = chefs[superior_index];
        add_inferior(chefs[superior_index], chefs[chef_index]);
    }
    int Q;
    scanf("%d", &Q);
    for (int i = 0; i < Q; i++) {
        int query_type;
        scanf("%d", &query_type);
        if (query_type == 1) {
            int chef_index, poison;
            scanf("%d %d", &chef_index, &poison);
            propagate_poison(chefs[chef_index], poison);
        } else if (query_type == 2) {
            int chef_index;
            scanf("%d", &chef_index);
            printf("%d\n", count_old_inferiors(chefs[chef_index]));
        }
    }
    return 0;
}

