import java.util.ArrayList;
import java.util.Scanner;

public class Main {
    // Define a class to represent a chef
    static class Chef {
        int index;
        int health;
        boolean is_old;
        Chef superior;
        ArrayList<Chef> inferiors;

        public Chef(int index) {
            this.index = index;
            this.health = 100;
            this.is_old = true;
            this.superior = null;
            this.inferiors = new ArrayList<>();
        }
    }

    // Function to add an inferior to a chef
    static void add_inferior(Chef chef, Chef inferior) {
        chef.inferiors.add(inferior);
    }

    // Function to propagate poison to inferiors
    static void propagate_poison(Chef chef, int poison) {
        if (chef.health <= 0) return;
        chef.health -= poison;
        if (chef.health <= 0) {
            chef.is_old = false;
        }
        for (Chef inferior : chef.inferiors) {
            propagate_poison(inferior, poison);
        }
    }

    // Function to count old inferiors
    static int count_old_inferiors(Chef chef) {
        int count = 0;
        for (Chef inferior : chef.inferiors) {
            if (inferior.is_old) count++;
            count += count_old_inferiors(inferior);
        }
        return count;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        Chef[] chefs = new Chef[N + 1];
        for (int i = 0; i <= N; i++) {
            chefs[i] = new Chef(i);
        }
        for (int i = 1; i <= N; i++) {
            int chef_index, superior_index;
            chef_index = scanner.nextInt();
            superior_index = scanner.nextInt();
            chefs[chef_index].superior = chefs[superior_index];
            add_inferior(chefs[superior_index], chefs[chef_index]);
        }
        int Q = scanner.nextInt();
        for (int i = 0; i < Q; i++) {
            int query_type = scanner.nextInt();
            if (query_type == 1) {
                int chef_index = scanner.nextInt();
                int poison = scanner.nextInt();
                propagate_poison(chefs[chef_index], poison);
            } else if (query_type == 2) {
                int chef_index = scanner.nextInt();
                System.out.println(count_old_inferiors(chefs[chef_index]));
            }
        }
    }
}

